import{_ as o,C as i,c as n,o as e,a3 as r,b as E,w as t,a as h,G as s,a4 as A}from"./chunks/framework.CTM16EAR.js";const q=JSON.parse('{"title":"第一阶段：记录时间","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pomodoro-technique/01-track-time.md","filePath":"guide/pomodoro-technique/01-track-time.md","lastUpdated":1778035726000}'),d={name:"guide/pomodoro-technique/01-track-time.md"};function u(B,a,c,g,p,m){const l=i("Mermaid");return e(),n("div",null,[a[1]||(a[1]=r('<h1 id="第一阶段-记录时间" tabindex="-1">第一阶段：记录时间 <a class="header-anchor" href="#第一阶段-记录时间" aria-label="Permalink to &quot;第一阶段：记录时间&quot;">​</a></h1><p><strong>目标</strong>：弄清完成一件事到底需要多久。</p><blockquote><p>界面分区、按钮名称以 <a href="./../reference/interface.html">软件界面</a> 与各篇 <code>功能参考</code> 为准；本文沿用番茄工作法的叙事顺序。</p></blockquote><h2 id="为什么要记录" tabindex="-1">为什么要记录 <a class="header-anchor" href="#为什么要记录" aria-label="Permalink to &quot;为什么要记录&quot;">​</a></h2><p>大多数人的时间感是模糊的：</p><ul><li>&quot;回复邮件，应该很快吧&quot;</li><li>&quot;写报告，大概一两个小时&quot;</li></ul><p><strong>实际情况往往和想象差很远。</strong></p><p>记录时间的目的是建立对任务的<strong>真实感知</strong>，而不是模糊的猜测。</p><h2 id="pomotention-的记录系统" tabindex="-1">Pomotention 的记录系统 <a class="header-anchor" href="#pomotention-的记录系统" aria-label="Permalink to &quot;Pomotention 的记录系统&quot;">​</a></h2><h3 id="活动清单-长期任务池" tabindex="-1">活动清单（长期任务池） <a class="header-anchor" href="#活动清单-长期任务池" aria-label="Permalink to &quot;活动清单（长期任务池）&quot;">​</a></h3><ul><li><strong>位置</strong>：首页<strong>右侧面板</strong>（与左侧时间表区、中间任务计划区 / 任务追踪区区分，见 <a href="./../reference/interface.html">软件界面</a>）</li><li><strong>用途</strong>：存放所有你想做的任务，不限于今天</li><li><strong>功能</strong>：支持当天筛选，查看历史任务</li></ul><p><strong>使用方法</strong>：</p><ol><li>想到什么任务，就添加到这里</li><li>为每个任务填写 <strong>预估番茄数</strong></li><li>任务完成后会自动归档</li></ol><h3 id="任务计划-当天执行" tabindex="-1">任务计划（当天执行） <a class="header-anchor" href="#任务计划-当天执行" aria-label="Permalink to &quot;任务计划（当天执行）&quot;">​</a></h3><ul><li><strong>位置</strong>：首页中间偏上<strong>任务计划区</strong></li><li><strong>用途</strong>：从活动清单中选择今天要做的任务（日 / 周 / 月视图见 <a href="./../reference/planner.html">任务计划</a>）</li><li><strong>特点</strong>：与活动清单数据同步</li></ul><p><strong>使用方法</strong>：</p><ol><li>每天早上（或前一天晚上）从活动清单选择任务</li><li>在任务计划中可以进行<strong>最多 3 段预估</strong>（与 <a href="./../reference/planner.html">任务计划</a> 中「果果」等说明一致）</li><li>执行任务时，番茄计时与这里关联</li></ol><h3 id="番茄时钟-实际记录" tabindex="-1">番茄时钟：实际记录 <a class="header-anchor" href="#番茄时钟-实际记录" aria-label="Permalink to &quot;番茄时钟：实际记录&quot;">​</a></h3><ul><li><strong>启动方式</strong>：点击任务旁的番茄图标（详见 <a href="./../reference/timer.html">番茄时钟</a>）</li><li><strong>默认时长</strong>：25 分钟工作 + 5 分钟休息</li><li><strong>记录内容</strong>：完成后自动记录实际用时</li></ul><h2 id="第一阶段操作流程" tabindex="-1">第一阶段操作流程 <a class="header-anchor" href="#第一阶段操作流程" aria-label="Permalink to &quot;第一阶段操作流程&quot;">​</a></h2>',20)),(e(),E(A,null,{default:t(()=>[s(l,{id:"mermaid-141",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20%E5%87%86%E5%A4%87%5B%E6%AF%8F%E6%97%A5%E5%BC%80%E5%A7%8B%5D%0A%20%20%20%20%20%20%20%20A%5B%E6%9F%A5%E7%9C%8B%E6%B4%BB%E5%8A%A8%E6%B8%85%E5%8D%95%5D%20--%3E%20B%5B%E9%80%89%E6%8B%A9%E4%BB%8A%E6%97%A5%E4%BB%BB%E5%8A%A1%5D%0A%20%20%20%20%20%20%20%20B%20--%3E%20C%5B%E7%BA%B3%E5%85%A5%E4%BB%BB%E5%8A%A1%E8%AE%A1%E5%88%92%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E9%A2%84%E4%BC%B0%5B%E9%A2%84%E4%BC%B0%E9%98%B6%E6%AE%B5%5D%0A%20%20%20%20%20%20%20%20D%5B%E5%A1%AB%E5%86%99%E9%A2%84%E4%BC%B0%E7%95%AA%E8%8C%84%E6%95%B0%5D%20--%3E%20E%7B%E6%B4%BB%E5%8A%A8%E6%B8%85%E5%8D%95%3A%20%E9%A6%96%E6%AC%A1%E9%A2%84%E4%BC%B0%7D%0A%20%20%20%20%20%20%20%20D%20--%3E%20F%7B%E4%BB%BB%E5%8A%A1%E8%AE%A1%E5%88%92%3A%20%E6%9C%80%E5%A4%9A3%E6%AE%B5%E9%A2%84%E4%BC%B0%7D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E6%89%A7%E8%A1%8C%5B%E6%89%A7%E8%A1%8C%E9%98%B6%E6%AE%B5%5D%0A%20%20%20%20%20%20%20%20G%5B%E5%BC%80%E5%A7%8B%E7%95%AA%E8%8C%84%E8%AE%A1%E6%97%B6%5D%20--%3E%20H%5B25%E5%88%86%E9%92%9F%E4%B8%93%E6%B3%A8%5D%0A%20%20%20%20%20%20%20%20H%20--%3E%20I%5B%E8%AE%B0%E5%BD%95%E5%AE%9E%E9%99%85%E7%94%A8%E6%97%B6%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E5%AF%B9%E6%AF%94%5B%E5%AF%B9%E6%AF%94%E5%88%86%E6%9E%90%5D%0A%20%20%20%20%20%20%20%20J%5B%E9%A2%84%E4%BC%B0%E7%95%AA%E8%8C%84%E6%95%B0%5D%20--%3E%20K%5B%E5%AE%9E%E9%99%85%E7%95%AA%E8%8C%84%E6%95%B0%5D%0A%20%20%20%20%20%20%20%20K%20--%3E%20L%5B%E5%B7%AE%E8%B7%9D%E5%88%86%E6%9E%90%5D%0A%20%20%20%20end%0A%0A%20%20%20%20%E5%87%86%E5%A4%87%20--%3E%20%E9%A2%84%E4%BC%B0%20--%3E%20%E6%89%A7%E8%A1%8C%20--%3E%20%E5%AF%B9%E6%AF%94%0A"})]),fallback:t(()=>a[0]||(a[0]=[h(" Loading... ")])),_:1})),a[2]||(a[2]=r('<h2 id="记录循环-从预估到实际" tabindex="-1">记录循环：从预估到实际 <a class="header-anchor" href="#记录循环-从预估到实际" aria-label="Permalink to &quot;记录循环：从预估到实际&quot;">​</a></h2><h3 id="_1-初次预估-活动清单" tabindex="-1">1. 初次预估（活动清单） <a class="header-anchor" href="#_1-初次预估-活动清单" aria-label="Permalink to &quot;1. 初次预估（活动清单）&quot;">​</a></h3><p>在活动清单中添加任务时，填写 <strong>预估番茄数</strong>：</p><ul><li>这是你<strong>第一反应</strong>的猜测</li><li>不要思考太久，凭直觉</li><li>记录格式：数字（如 2 表示预估 2 个番茄）</li></ul><h3 id="_2-多段预估-任务计划" tabindex="-1">2. 多段预估（任务计划） <a class="header-anchor" href="#_2-多段预估-任务计划" aria-label="Permalink to &quot;2. 多段预估（任务计划）&quot;">​</a></h3><p>将任务纳入任务计划后，可以细化预估：</p><ul><li><strong>最多 3 段预估</strong>：表示任务可以分为 1-3 个部分</li><li>每段对应一个番茄数</li><li>例如：写报告 = 第一段（构思，1番茄）+ 第二段（写作，2番茄）+ 第三段（修改，1番茄）</li></ul><blockquote><p><strong>注意</strong>：活动清单与任务计划中的预估数据是同步的，修改一边会更新另一边。</p></blockquote><h3 id="_3-实际记录-任务追踪" tabindex="-1">3. 实际记录（任务追踪） <a class="header-anchor" href="#_3-实际记录-任务追踪" aria-label="Permalink to &quot;3. 实际记录（任务追踪）&quot;">​</a></h3><p>完成番茄后，按界面提示在记录流程中标记结果（控件见 <a href="./../appendix/buttons.html">附录：按钮一览</a>、<a href="./../reference/task.html">任务追踪</a>）：</p><ul><li>标记番茄是否完成（完整/部分/未完成）</li><li>记录实际用时</li><li>系统自动对比预估 vs 实际</li></ul><h2 id="记录数据看哪里" tabindex="-1">记录数据看哪里 <a class="header-anchor" href="#记录数据看哪里" aria-label="Permalink to &quot;记录数据看哪里&quot;">​</a></h2><h3 id="当日记录" tabindex="-1">当日记录 <a class="header-anchor" href="#当日记录" aria-label="Permalink to &quot;当日记录&quot;">​</a></h3><p>任务计划视图承担<strong>当日计划与执行对照</strong>的主要展示（详见 <a href="./../reference/planner.html">任务计划</a>）：</p><ul><li>显示今天计划了什么</li><li>显示实际完成了什么</li><li>显示预估与实际的差距</li></ul><h3 id="历史记录" tabindex="-1">历史记录 <a class="header-anchor" href="#历史记录" aria-label="Permalink to &quot;历史记录&quot;">​</a></h3><ul><li><a href="./../reference/search.html">数据查看</a>：检索历史任务与记录</li><li><a href="./../archive/data.html">数据与迁移</a> 等：备份、导出与数据相关说明</li><li><a href="./../reference/chart.html">数据趋势</a>：在「仪表盘」等入口查看趋势（见 <a href="./../reference/interface.html">软件界面</a>）</li></ul><h2 id="第一阶段的常见问题" tabindex="-1">第一阶段的常见问题 <a class="header-anchor" href="#第一阶段的常见问题" aria-label="Permalink to &quot;第一阶段的常见问题&quot;">​</a></h2><p><strong>Q: 预估不准怎么办？</strong><br> A: 正常。第一阶段的目标就是发现&quot;不准&quot;，记录一段时间后你会越来越准。</p><p><strong>Q: 任务只做了一部分怎么办？</strong><br> A: 在任务追踪中标记为&quot;部分完成&quot;，记录实际用时，剩余部分下次继续。</p><p><strong>Q: 一个番茄做不完一个任务怎么办？</strong><br> A: 大任务拆分。在任务计划中使用多段预估，把任务拆成 1-3 个部分。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./02-handle-interruptions.html">02-handle-interruptions.md</a>，学习如何应对打断。</li></ul><h2 id="本阶段检查清单" tabindex="-1">本阶段检查清单 <a class="header-anchor" href="#本阶段检查清单" aria-label="Permalink to &quot;本阶段检查清单&quot;">​</a></h2><ul><li>[ ] 每天从活动清单选择任务到任务计划</li><li>[ ] 为每个任务填写预估番茄数</li><li>[ ] 使用番茄时钟记录实际用时</li><li>[ ] 在任务追踪中标记完成状态</li><li>[ ] 每周查看一次 <a href="./../reference/chart.html">数据趋势</a>，对比预估 vs 实际趋势</li></ul>',25))])}const b=o(d,[["render",u]]);export{q as __pageData,b as default};
